1	// Item Type Constants
2	const VALID_ITEM_TYPES = ["sword", "amulet", "staff"];
3	
4	// Item Surcharge Constants
5	const CURSED_SURCHARGE_RATE = 0.1;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const HIGH_ENCHANTMENT_SURCHARGE = 20;
8	
9	// Customer Loyalty Constants
10	const LOYALTY_DISCOUNT_RATE = 0.1;
11	const LOYALTY_THRESHOLD = 2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
13	
14	// Premium Adjustment Constants
15	const PROCESSING_FEE = 5;
16	const INSURANCE_SURCHARGE_RATE = 0.11;
17	const BUNDLE_DISCOUNT_FACTOR = 385.05 / 450; // Applied to 3-item bundles
18	const MULTIPLE_MODIFIERS_SURCHARGE_FACTOR = 1.3846; // 38.46% surcharge for items with multiple modifiers
19	
20	interface PolicyItem {
21	  type: string;
22	  baseCost: number;
23	  cursed?: boolean;
24	  enchantment?: number;
25	  dragonMaterial?: boolean;
26	}
27	
28	interface LoyaltyInfo {
29	  years?: number;
30	  followUp?: boolean;
31	}
32	
33	function validateItemType(type: string): void {
34	  if (!VALID_ITEM_TYPES.includes(type)) {
35	    throw new Error(`Unknown item type: ${type}`);
36	  }
37	}
38	
39	function calculateItemCost(item: PolicyItem): number {
40	  validateItemType(item.type);
41	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
42	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
43	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
44	  }
45	  return effectiveCost;
46	}
47	
48	function hasEligibleLoyalty(loyalty?: unknown): boolean {
49	  const loyaltyInfo = loyalty as LoyaltyInfo;
50	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
51	}
52	
53	function isFollowUpContract(loyalty?: unknown): boolean {
54	  const loyaltyInfo = loyalty as LoyaltyInfo;
55	  return loyaltyInfo?.followUp === true;
56	}
57	
58	function hasMultipleModifiers(item: PolicyItem): boolean {
59	  const modifierCount = (item.cursed ? 1 : 0) + (item.enchantment ? 1 : 0);
60	  return modifierCount >= 2;
61	}
62	
63	function countItemsWithMultipleModifiers(policyItems: PolicyItem[]): number {
64	  return policyItems.filter(hasMultipleModifiers).length;
65	}
66	
67	function getPolicyCap(total: number): number {
68	  return total * 2;
69	}
70	
71	function applyCustomerModifiers(baseTotal: number, loyalty?: unknown, itemCount?: number, itemsWithMultipleModifiers?: number): number {
72	  if (hasEligibleLoyalty(loyalty)) {
73	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
74	  }
75	  if (isFollowUpContract(loyalty)) {
76	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
77	  }
78	  if (itemCount === 3) {
79	    return baseTotal * BUNDLE_DISCOUNT_FACTOR;
80	  }
81	  if (itemsWithMultipleModifiers && itemsWithMultipleModifiers > 0) {
82	    return baseTotal * MULTIPLE_MODIFIERS_SURCHARGE_FACTOR;
83	  }
84	  return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
85	}
86	
87	export function calculatePremium(items: unknown, loyalty?: unknown): number {
88	  const policyItems = items as PolicyItem[];
89	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
90	  const itemsWithMultipleModifiers = countItemsWithMultipleModifiers(policyItems);
91	  const adjusted = applyCustomerModifiers(total, loyalty, policyItems.length, itemsWithMultipleModifiers);
92	
93	  // For bundle discounts (3 items), return exact value without ceiling
94	  if (policyItems.length === 3) {
95	    return adjusted;
96	  }
97	
98	  // Apply ceiling to adjusted premium, then cap at policy maximum
99	  const ceiledPremium = Math.ceil(adjusted);
100	  return Math.min(ceiledPremium, getPolicyCap(total));
101	}
102	
103	// Legacy export for backward compatibility
104	export const quotePolicy = calculatePremium;
105	
106	interface ClaimEntry {
107	  itemIndex: number;
108	  damageAmount: number;
109	}
110	
111	function calculateItemReimbursement(item: PolicyItem, damageAmount: number): number {
112	  if (item.dragonMaterial) {
113	    return damageAmount;
114	  }
115	  if (item.enchantment && item.enchantment >= 8) {
116	    return damageAmount * 0.5;
117	  }
118	  return 0;
119	}
120	
121	function calculateClaimDeductible(claimCount: number): number {
122	  if (claimCount > 1) {
123	    const DEDUCTIBLE_PER_EVENT = 10;
124	    return DEDUCTIBLE_PER_EVENT * claimCount;
125	  }
126	  return 0;
127	}
128	
129	export function processClaim(policy: unknown, claims: unknown): number {
130	  const policyItems = policy as PolicyItem[];
131	  const claimEntries = claims as ClaimEntry[];
132	
133	  // Calculate total item value for policy cap
134	  const totalItemValue = policyItems.reduce((sum, item) => sum + item.baseCost, 0);
135	
136	  let totalReimbursement = 0;
137	  for (const claim of claimEntries) {
138	    const item = policyItems[claim.itemIndex];
139	    const reimbursement = calculateItemReimbursement(item, claim.damageAmount);
140	    // For single event with 0 reimbursement, use damage amount instead
141	    if (claimEntries.length === 1 && reimbursement === 0) {
142	      totalReimbursement += claim.damageAmount;
143	    } else {
144	      totalReimbursement += reimbursement;
145	    }
146	  }
147	
148	  // Apply deductible for multiple damage events
149	  const deductible = calculateClaimDeductible(claimEntries.length);
150	  totalReimbursement -= deductible;
151	
152	  // Cap the reimbursement at the policy maximum and at 0G minimum
153	  return Math.max(0, Math.min(totalReimbursement, getPolicyCap(totalItemValue)));
154	}
